import Navbar from "../components/Navbar";

const getInitials = (name) => name.replace("Chef ", "").split(" ").map(n => n[0]).join("").slice(0, 2);

export default function RecipeDetailPage({ recipe, setPage }) {
  if (!recipe) return null;
  const stepImages = recipe.stepImages || [];
  let imgIdx = 0;

  return (
    <div style={{ background:"#fff", minHeight:"100vh" }}>
      <Navbar setPage={setPage} />
      <div style={{ maxWidth:1060, margin:"0 auto", padding:"32px 24px 80px", display:"grid", gridTemplateColumns:"1fr 300px", gap:40, alignItems:"start" }}>

        {/* LEFT */}
        <div>
          <div style={{ fontSize:11, color:"#999", letterSpacing:".5px", textTransform:"uppercase", marginBottom:20 }}>
            <button onClick={() => setPage("home")} style={{ background:"none", border:"none", color:"#999", fontSize:11, textTransform:"uppercase", letterSpacing:".5px" }}>Recipes</button>
            {" › "}<span style={{ color:"#e85d2f", fontWeight:600 }}>{recipe.tag}</span>
          </div>

          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:36, fontWeight:900, lineHeight:1.1, marginBottom:14, color:"#111" }}>{recipe.title}</h1>

          <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20, flexWrap:"wrap" }}>
            <div style={{ width:34, height:34, borderRadius:"50%", background:"linear-gradient(135deg,#e85d2f,#c0392b)", display:"flex", alignItems:"center", justifyContent:"center", color:"#fff", fontSize:13, fontWeight:700 }}>{getInitials(recipe.chef)}</div>
            <div>
              <div style={{ fontSize:13, fontWeight:500, color:"#333" }}>{recipe.chef}</div>
              <div style={{ fontSize:12, color:"#aaa" }}>Published Oct 24, 2023</div>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:4, fontSize:13, fontWeight:600, color:"#e85d2f" }}>
              ★ {recipe.rating} <span style={{ color:"#999", fontWeight:400 }}>({recipe.reviews} Reviews)</span>
            </div>
          </div>

          <img src={recipe.image} alt={recipe.title} style={{ width:"100%", height:360, objectFit:"cover", borderRadius:14, marginBottom:36, display:"block" }} />

          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:40 }}>
            <div>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:"#111", marginBottom:18 }}>
                Ingredients <span style={{ fontSize:14, color:"#aaa", fontWeight:400 }}>{recipe.ingredients.length} items</span>
              </h2>
              <ul style={{ listStyle:"none" }}>
                {recipe.ingredients.length > 0 ? recipe.ingredients.map((ing, i) => (
                  <li key={i} style={{ padding:"12px 0", borderBottom:"1px solid #f0ede6" }}>
                    <div style={{ fontSize:14, fontWeight:600, color:"#222", marginBottom:2 }}>{ing.name}</div>
                    <div style={{ fontSize:12, color:"#aaa", fontWeight:300 }}>{ing.note}</div>
                  </li>
                )) : <li style={{ color:"#bbb", fontSize:13 }}>Ingredients coming soon...</li>}
              </ul>
            </div>
            <div>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:"#111", marginBottom:18 }}>Instructions</h2>
              {recipe.steps.length > 0 ? recipe.steps.map((step, i) => {
                const img = step.hasImage ? stepImages[imgIdx++] : null;
                return (
                  <div key={i} style={{ display:"flex", gap:20, marginBottom:32 }}>
                    <div style={{ width:34, height:34, borderRadius:"50%", background:"#e85d2f", color:"#fff", fontSize:14, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:2 }}>{i+1}</div>
                    <div>
                      <div style={{ fontSize:16, fontWeight:700, color:"#111", marginBottom:8 }}>{step.title}</div>
                      <div style={{ fontSize:14, color:"#555", lineHeight:1.65, fontWeight:300 }}>{step.body}</div>
                      {img && <img src={img} alt={step.title} style={{ width:"100%", height:200, objectFit:"cover", borderRadius:10, marginTop:14 }} />}
                    </div>
                  </div>
                );
              }) : <div style={{ color:"#bbb", fontSize:13 }}>Instructions coming soon...</div>}
            </div>
          </div>
        </div>

        {/* RIGHT */}
        <div style={{ position:"sticky", top:80 }}>
          <div style={{ background:"#fafaf8", border:"1.5px solid #ede9e0", borderRadius:14, padding:22, marginBottom:18 }}>
            <div style={{ fontSize:13, fontWeight:700, color:"#e85d2f", letterSpacing:".5px", textTransform:"uppercase", marginBottom:16 }}>📋 Recipe Overview</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16 }}>
              {[["⏱","Prep Time",recipe.prepTime],["🔥","Cook Time",recipe.cookTime],["👥","Servings",`${recipe.servings} people`],["⚡","Calories",`${recipe.calories} kcal`],["📊","Difficulty",recipe.difficulty],["🌍","Cuisine",recipe.cuisine]].map(([icon, label, val]) => (
                <div key={label}>
                  <div style={{ fontSize:20, marginBottom:4 }}>{icon}</div>
                  <div style={{ fontSize:11, color:"#aaa", fontWeight:500, textTransform:"uppercase", letterSpacing:".4px" }}>{label}</div>
                  <div style={{ fontSize:15, fontWeight:700, color:"#111" }}>{val}</div>
                </div>
              ))}
            </div>
          </div>
          <button style={{ width:"100%", background:"#fff", border:"1.5px solid #e85d2f", color:"#e85d2f", padding:12, borderRadius:9, fontSize:13, fontWeight:600, display:"flex", alignItems:"center", justifyContent:"center", gap:7, marginBottom:18 }}>🖨 Print Recipe</button>
          {recipe.tip && (
            <div style={{ background:"#fff9f7", border:"1.5px solid #f5d5c8", borderRadius:14, padding:20 }}>
              <div style={{ fontSize:11, fontWeight:700, color:"#e85d2f", textTransform:"uppercase", letterSpacing:".6px", marginBottom:10 }}>Chef's Secret Tip</div>
              <div style={{ fontSize:13, color:"#666", lineHeight:1.6, fontStyle:"italic", fontWeight:300 }}>"{recipe.tip}"</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
